                    "name": str(manifest.get("name") or entry.name),
                    "version": str(manifest.get("version") or "unknown"),
                    "path": str(entry),
                    "verified": verified_marker.exists(),
                    "policy_sha256": str(manifest.get("policy_sha256") or ""),
                }
            )

        return installed

    def verify_installed(self, name: str) -> bool:
        """Re-verify an installed pack against registry signature and pack contents."""
        destination = self._policies_dir / name
        policy_path = destination / "policy.yaml"
        manifest_path = destination / "manifest.json"

        if not policy_path.exists() or not manifest_path.exists():
            raise RegistryInstallError(
                f"Policy pack '{name}' is not installed at {destination}"
            )

        try:
            local_manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except json.JSONDecodeError as exc:
            raise RegistryInstallError(
                f"Installed manifest is invalid JSON: {manifest_path}"
            ) from exc

        version = local_manifest.get("version")
        local_policy = policy_path.read_text(encoding="utf-8")
        local_sha = hashlib.sha256(local_policy.encode("utf-8")).hexdigest()

        pack = self.fetch(name=name, version=str(version) if version else None)
        self.verify_signature(pack)

        if local_sha != pack.policy_sha256:
            raise RegistryVerificationError(
                f"Installed policy pack '{name}' does not match signed registry content"
            )

        verified_marker = destination / "verified"
        verified_marker.write_text(local_sha, encoding="utf-8")
        local_manifest["verified"] = True
        local_manifest["verified_at"] = _utc_now_iso()
        manifest_path.write_text(
            json.dumps(local_manifest, indent=2, sort_keys=True),
            encoding="utf-8",
        )
        return True

    def remove(self, name: str) -> bool:
        """Remove an installed policy pack and corresponding lockfile entry."""
        destination = self._policies_dir / name
        if not destination.exists():
            return False

        if destination.is_dir():
            shutil.rmtree(destination)
        else:
            destination.unlink()

        if self._lockfile_path.exists():
            try:
                lock = json.loads(self._lockfile_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError as exc:
                raise RegistryInstallError(
                    f"Lockfile is invalid JSON: {self._lockfile_path}"
                ) from exc

            policies = lock.get("policies")
            if isinstance(policies, dict) and name in policies:
                del policies[name]
                lock["updated_at"] = _utc_now_iso()
                self._lockfile_path.write_text(
                    json.dumps(lock, indent=2, sort_keys=True),
                    encoding="utf-8",
                )

        return True

    def _update_lockfile(self, pack: PolicyPack) -> None:
        """Update or create the policy lockfile for an installed pack."""
        lock = {
            "version": 1,
            "updated_at": _utc_now_iso(),
            "policies": {},
        }

        if self._lockfile_path.exists():
            try:
                lock = json.loads(self._lockfile_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError as exc:
                raise RegistryInstallError(
                    f"Lockfile is invalid JSON: {self._lockfile_path}"
                ) from exc

            if "policies" not in lock or not isinstance(lock["policies"], dict):
                lock["policies"] = {}

            lock["updated_at"] = _utc_now_iso()

        lock["policies"][pack.name] = {
            "version": pack.version,
            "sha256": pack.policy_sha256,
            "manifest_sha256": pack.manifest_sha256,
            "installed_at": _utc_now_iso(),
        }

        self._lockfile_path.parent.mkdir(parents=True, exist_ok=True)
        self._lockfile_path.write_text(
            json.dumps(lock, indent=2, sort_keys=True),
            encoding="utf-8",
        )

from __future__ import annotations

import base64
import hashlib
import json
import os
import shutil
from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path
from tempfile import TemporaryDirectory
from typing import Any, Optional
from urllib.parse import urlencode, urljoin
from urllib.request import urlopen

from cryptography.hazmat.primitives.asymmetric.ed25519 import (
    Ed25519PublicKey,
)

from .exceptions import (
    RegistryFetchError,
    RegistryInstallError,
    RegistryVerificationError,
)


def _utc_now_iso() -> str:
    """Return the current UTC time in ISO 8601 format."""
    return datetime.now(timezone.utc).isoformat()


@dataclass(frozen=True)
class PolicyPack:
    """A signed policy pack fetched from a remote policy registry."""

    name: str
    version: str
    policy_yaml: str
    manifest: dict[str, Any]
    signature: bytes
    public_key: bytes
    source: Optional[str] = None

    @property
    def policy_sha256(self) -> str:
        """Return the SHA-256 hash of the raw policy YAML bytes."""
        return hashlib.sha256(self.policy_yaml.encode("utf-8")).hexdigest()

    @property
    def manifest_sha256(self) -> str:
        """Return the SHA-256 hash of canonical manifest JSON bytes."""
        canonical = json.dumps(self.manifest, sort_keys=True, separators=(",", ":"))
        return hashlib.sha256(canonical.encode("utf-8")).hexdigest()

    def signed_payload(self) -> bytes:
        """Return canonical bytes used for Ed25519 signature verification."""
        payload = {
            "name": self.name,
            "version": self.version,
            "policy_yaml": self.policy_yaml,
            "manifest": self.manifest,
        }
        canonical = json.dumps(payload, sort_keys=True, separators=(",", ":"))
        return canonical.encode("utf-8")


class RegistryClient:
    """Client for installing and verifying signed policy packs from a registry."""

    def __init__(
        self,
        registry_url: str,
        policies_dir: Optional[Path] = None,
        lockfile_path: Optional[Path] = None,
        timeout_seconds: float = 10.0,
    ):
        """Initialize a registry client with local install and lockfile paths."""
        self._registry_url = registry_url.rstrip("/") + "/"
        home = Path.home()
        self._policies_dir = policies_dir or (home / ".megent" / "policies")
        self._lockfile_path = lockfile_path or (Path.cwd() / "megent.lock")
        self._timeout_seconds = timeout_seconds

    @property
    def policies_dir(self) -> Path:
        """Return the local directory where policy packs are installed."""
        return self._policies_dir

    @property
    def lockfile_path(self) -> Path:
        """Return the path to the Megent policy lockfile."""
        return self._lockfile_path

    def fetch(self, name: str, version: Optional[str] = None) -> PolicyPack:
        """Fetch a policy pack payload from the configured registry endpoint."""
        endpoint = urljoin(self._registry_url, f"policies/{name}")
        if version:
            endpoint = f"{endpoint}?{urlencode({'version': version})}"

        try:
            with urlopen(endpoint, timeout=self._timeout_seconds) as response:
                payload = json.load(response)
        except Exception as exc:  # noqa: BLE001
            raise RegistryFetchError(f"Failed to fetch policy pack '{name}': {exc}") from exc

        try:
            fetched_name = str(payload.get("name") or name)
            fetched_version = str(payload.get("version") or version or "latest")
            policy_yaml = str(payload["policy_yaml"])
            manifest = payload.get("manifest") or {}
            signature_b64 = payload["signature"]
            public_key_b64 = payload["public_key"]

            signature = base64.b64decode(signature_b64)
            public_key = base64.b64decode(public_key_b64)
        except Exception as exc:  # noqa: BLE001
            raise RegistryFetchError(
                f"Registry response for '{name}' is missing required fields"
            ) from exc

        return PolicyPack(
            name=fetched_name,
            version=fetched_version,
            policy_yaml=policy_yaml,
            manifest=manifest,
            signature=signature,
            public_key=public_key,
            source=endpoint,
        )

    def verify_signature(self, pack: PolicyPack) -> bool:
        """Verify an Ed25519 signature for the canonical policy pack payload."""
        try:
            public_key = Ed25519PublicKey.from_public_bytes(pack.public_key)
            public_key.verify(pack.signature, pack.signed_payload())
            return True
        except Exception as exc:  # noqa: BLE001
            raise RegistryVerificationError(
                f"Signature verification failed for '{pack.name}@{pack.version}'"
            ) from exc

    def install(
        self,
        name: str,
        version: Optional[str] = None,
        verify: bool = True,
    ) -> PolicyPack:
        """Fetch and install a policy pack locally, optionally verifying signature."""
        pack = self.fetch(name=name, version=version)
        if verify:
            self.verify_signature(pack)

        destination = self._policies_dir / pack.name
        try:
            self._policies_dir.mkdir(parents=True, exist_ok=True)
            destination.parent.mkdir(parents=True, exist_ok=True)

            with TemporaryDirectory(prefix="megent-policy-") as tmp_dir:
                tmp_path = Path(tmp_dir)
                policy_path = tmp_path / "policy.yaml"
                manifest_path = tmp_path / "manifest.json"
                verified_marker_path = tmp_path / "verified"

                install_manifest = dict(pack.manifest)
                install_manifest.update(
                    {
                        "name": pack.name,
                        "version": pack.version,
                        "verified": verify,
                        "policy_sha256": pack.policy_sha256,
                        "manifest_sha256": pack.manifest_sha256,
                        "installed_at": _utc_now_iso(),
                        "source": pack.source,
                    }
                )

                policy_path.write_text(pack.policy_yaml, encoding="utf-8")
                manifest_path.write_text(
                    json.dumps(install_manifest, indent=2, sort_keys=True),
                    encoding="utf-8",
                )
                if verify:
                    verified_marker_path.write_text(pack.policy_sha256, encoding="utf-8")

                if destination.exists():
                    if destination.is_dir():
                        shutil.rmtree(destination)
                    else:
                        destination.unlink()
                destination.mkdir(parents=True, exist_ok=True)

                files = ["policy.yaml", "manifest.json"]
                if verify:
                    files.append("verified")

                for filename in files:
                    source = tmp_path / filename
                    target = destination / filename
                    os.replace(source, target)

            self._update_lockfile(pack)
        except RegistryInstallError:
            raise
        except Exception as exc:  # noqa: BLE001
            raise RegistryInstallError(
                f"Failed to install policy pack '{pack.name}@{pack.version}'"
            ) from exc

        return pack

    def list_installed(self) -> list[dict[str, Any]]:
        """List installed packs discovered under the local policies directory."""
        if not self._policies_dir.exists():
            return []

        installed: list[dict[str, Any]] = []
        for entry in sorted(self._policies_dir.iterdir(), key=lambda p: p.name):
            if not entry.is_dir():
                continue

            manifest_path = entry / "manifest.json"
            verified_marker = entry / "verified"
            policy_path = entry / "policy.yaml"

            if not manifest_path.exists() or not policy_path.exists():
                continue

            try:
                manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError as exc:
                raise RegistryInstallError(
                    f"Installed manifest is invalid JSON: {manifest_path}"
                ) from exc

            installed.append(
                {
                    "name": str(manifest.get("name") or entry.name),
                    "version": str(manifest.get("version") or "unknown"),
                    "publisher": str(manifest.get("publisher") or "unknown"),
                    "path": str(entry),
                    "verified": verified_marker.exists(),
                    "policy_sha256": str(manifest.get("policy_sha256") or ""),
                }
            )

        return installed

    def verify_installed(self, name: str) -> bool:
        """Re-verify an installed pack against registry signature and pack contents."""
        destination = self._policies_dir / name
        policy_path = destination / "policy.yaml"
        manifest_path = destination / "manifest.json"

        if not policy_path.exists() or not manifest_path.exists():
            raise RegistryInstallError(
                f"Policy pack '{name}' is not installed at {destination}"
            )

        try:
            local_manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except json.JSONDecodeError as exc:
            raise RegistryInstallError(
                f"Installed manifest is invalid JSON: {manifest_path}"
            ) from exc

        version = local_manifest.get("version")
        local_policy = policy_path.read_text(encoding="utf-8")
        local_sha = hashlib.sha256(local_policy.encode("utf-8")).hexdigest()

        pack = self.fetch(name=name, version=str(version) if version else None)
        self.verify_signature(pack)

        if local_sha != pack.policy_sha256:
            raise RegistryVerificationError(
                f"Installed policy pack '{name}' does not match signed registry content"
            )

        verified_marker = destination / "verified"
        verified_marker.write_text(local_sha, encoding="utf-8")
        local_manifest["verified"] = True
        local_manifest["verified_at"] = _utc_now_iso()
        manifest_path.write_text(
            json.dumps(local_manifest, indent=2, sort_keys=True),
            encoding="utf-8",
        )
        return True

    def remove(self, name: str) -> bool:
        """Remove an installed policy pack and corresponding lockfile entry."""
        destination = self._policies_dir / name
        if not destination.exists():
            return False

        if destination.is_dir():
            shutil.rmtree(destination)
        else:
            destination.unlink()

        if self._lockfile_path.exists():
            try:
                lock = json.loads(self._lockfile_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError as exc:
                raise RegistryInstallError(
                    f"Lockfile is invalid JSON: {self._lockfile_path}"
                ) from exc

            policies = lock.get("policies")
            if isinstance(policies, dict) and name in policies:
                del policies[name]
                lock["updated_at"] = _utc_now_iso()
                self._lockfile_path.write_text(
                    json.dumps(lock, indent=2, sort_keys=True),
                    encoding="utf-8",
                )

        return True

    def _update_lockfile(self, pack: PolicyPack) -> None:
        """Update or create the policy lockfile for an installed pack."""
        lock = {
            "version": 1,
            "updated_at": _utc_now_iso(),
            "policies": {},
        }

        if self._lockfile_path.exists():
            try:
                lock = json.loads(self._lockfile_path.read_text(encoding="utf-8"))
            except json.JSONDecodeError as exc:
                raise RegistryInstallError(
                    f"Lockfile is invalid JSON: {self._lockfile_path}"
                ) from exc

            if "policies" not in lock or not isinstance(lock["policies"], dict):
                lock["policies"] = {}

            lock["updated_at"] = _utc_now_iso()

        lock["policies"][pack.name] = {
            "version": pack.version,
            "sha256": pack.policy_sha256,
            "manifest_sha256": pack.manifest_sha256,
            "installed_at": _utc_now_iso(),
        }

        self._lockfile_path.parent.mkdir(parents=True, exist_ok=True)
        self._lockfile_path.write_text(
            json.dumps(lock, indent=2, sort_keys=True),
            encoding="utf-8",
        )

from __future__ import annotations

from dataclasses import dataclass

import pytest

from megent.cli import main
from megent.exceptions import RegistryVerificationError


@dataclass
class _FakePack:
    name: str
    version: str


class _FakeClient:
    def __init__(self) -> None:
        self.install_calls: list[tuple[str, str | None, bool]] = []
        self.verify_should_fail = False

    def install(self, name: str, version: str | None = None, verify: bool = True) -> _FakePack:
        self.install_calls.append((name, version, verify))
        return _FakePack(name=name, version=version or "latest")

    def list_installed(self) -> list[dict[str, object]]:
        return []

    def verify_installed(self, name: str) -> bool:
        if self.verify_should_fail:
            raise RegistryVerificationError("invalid signature")
        return True

    def remove(self, name: str) -> bool:
        return True


def test_cli_policy_install_no_verify_passes_verify_false(monkeypatch: pytest.MonkeyPatch) -> None:
    fake = _FakeClient()

    import megent.cli as cli_module

    monkeypatch.setattr(cli_module, "_client_for_args", lambda args: fake)

    exit_code = main(["policy", "install", "stripe", "--no-verify"])
    assert exit_code == 0
    assert fake.install_calls == [("stripe", None, False)]


def test_cli_policy_verify_returns_exit_code_1_for_invalid_signature(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    fake = _FakeClient()
    fake.verify_should_fail = True

    import megent.cli as cli_module

    monkeypatch.setattr(cli_module, "_client_for_args", lambda args: fake)

    exit_code = main(["policy", "verify", "stripe"])
    assert exit_code == 1

from __future__ import annotations

import os
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any, Optional

try:
    import yaml
except ImportError as exc:  # pragma: no cover
    raise ImportError("Install PyYAML: pip install pyyaml") from exc

from .exceptions import PolicyLoadError


@dataclass
class ToolPolicy:
    name: str
    allowed: bool = False
    pii_mask: list[str] = field(default_factory=list)
    # Future: rate_limit, require_approval, allowed_args, ...


@dataclass
class Policy:
    version: str = "1"
    default_action: str = "deny"          # deny | allow
    tools: dict[str, ToolPolicy] = field(default_factory=dict)
    pii_mask: list[str] = field(default_factory=list)  # global PII mask

    def is_allowed(self, tool_name: str) -> bool:
        if tool_name in self.tools:
            return self.tools[tool_name].allowed
        return self.default_action == "allow"

    def pii_fields_for(self, tool_name: str) -> list[str]:
        """Merge global + tool-level PII mask fields."""
        tool_fields = self.tools.get(tool_name, ToolPolicy(tool_name)).pii_mask
        return list(set(self.pii_mask + tool_fields))


# ---------------------------------------------------------------------------
# Loader
# ---------------------------------------------------------------------------

def _parse_tool(name: str, raw: Any) -> ToolPolicy:
    if raw is None:
        raw = {}
    if isinstance(raw, bool):
        return ToolPolicy(name=name, allowed=raw)
    return ToolPolicy(
        name=name,
        allowed=bool(raw.get("allow", False)),
        pii_mask=raw.get("pii_mask", []),
    )


def _looks_like_pack_name(value: str) -> bool:
    if not value:
        return False
    if "/" in value or "\\" in value:
        return False
    return Path(value).suffix == ""


def _resolve_pack_policy_path(pack_name: str) -> Path:
    pack_dir = _installed_policies_root() / pack_name
    policy_path = pack_dir / "policy.yaml"
    verified_marker = pack_dir / "verified"

    if not policy_path.exists():
        raise PolicyLoadError(
            f"Policy pack '{pack_name}' is not installed at {policy_path}. "
            f"Run `megent policy install {pack_name}`."
        )

    if not verified_marker.exists():
        raise PolicyLoadError(
            f"Policy pack '{pack_name}' is not verified. "
            f"Run `megent policy verify {pack_name}`."
        )

    return policy_path


def _installed_policies_root() -> Path:
    return Path.home() / ".megent" / "policies"


def _is_within(path: Path, root: Path) -> bool:
    try:
        path.resolve(strict=False).relative_to(root.resolve(strict=False))
        return True
    except ValueError:
        return False


def _require_verified_if_installed_path(policy_path: Path) -> None:
    policies_root = _installed_policies_root()
    if not _is_within(policy_path, policies_root):
        return

    relative = policy_path.resolve(strict=False).relative_to(
        policies_root.resolve(strict=False)
    )
    if not relative.parts:
        return

    pack_name = relative.parts[0]
    verified_marker = policies_root / pack_name / "verified"
    if not verified_marker.exists():
        raise PolicyLoadError(
            f"Policy pack '{pack_name}' is not verified. "
            f"Run `megent policy verify {pack_name}`."
        )


def _resolve_policy_location(path: Optional[str]) -> str:
    candidate = path or os.environ.get("MEGENT_POLICY")
    if candidate:
        if _looks_like_pack_name(candidate):
            return str(_resolve_pack_policy_path(candidate))
        return candidate
    return str(Path.cwd() / "megent.yaml")


def load_policy(path: Optional[str] = None) -> Policy:
    """
    Load a policy from a YAML file.

        Resolution order:
            1. Explicit `path` argument
            2. MEGENT_POLICY env var
            3. Named registry pack (no path separators and no extension)
                 -> ~/.megent/policies/<name>/policy.yaml
            4. ./megent.yaml in the current working directory
    """
    resolved = _resolve_policy_location(path)
    _require_verified_if_installed_path(Path(resolved))

    try:
        with open(resolved, "r") as f:
            raw = yaml.safe_load(f) or {}
    except FileNotFoundError:
        raise PolicyLoadError(f"Policy file not found: {resolved}")
    except yaml.YAMLError as exc:
        raise PolicyLoadError(f"Invalid YAML in policy file: {exc}")

    tools_raw: dict[str, Any] = raw.get("tools", {})
    tools = {name: _parse_tool(name, cfg) for name, cfg in tools_raw.items()}

    return Policy(
        version=str(raw.get("version", "1")),
        default_action=raw.get("default_action", "deny"),
        tools=tools,
        pii_mask=raw.get("pii_mask", []),
    )

